// Import Firestore database
import { db } from '../config/firebase';
import { collection, query, getDocs, getDoc, doc, setDoc, where } from "firebase/firestore";
import { useState } from 'react';
import ReactDOM from 'react-dom/client';

 
async function Read() {

    const docRef = doc(db, "City", "Leuven");
    const docSnap = await getDoc(docRef);
    
    if (docSnap.exists()) {
      const data = docSnap.data();
      
      const [cleanarray] = Object.values(data)
      const iterator = cleanarray.values()

      for (const value of iterator) {
        console.log(value);
        const id = value
        const docRef2 = doc(db, "Routes", id);
        const docSnap2 = await getDoc(docRef2);
        // console.log(docSnap2)
      }

        
    } else {
      // doc.data() will be undefined in this case
      console.log("No such document!");
    }

     
    
}
 
export default Read;
